   432→/* Populate the length object and try gluing it to the next chunk. */
   433→void setDeferredAggregateLen(client *c, void *node, long length, char prefix) {
   434→    listNode *ln = (listNode*)node;
   435→    clientReplyBlock *next;
   436→    char lenstr[128];
   437→    size_t lenstr_len = sprintf(lenstr, "%c%ld\r\n", prefix, length);
   438→
   439→    /* Abort when *node is NULL: when the client should not accept writes
   440→     * we return NULL in addReplyDeferredLen() */
   441→    if (node == NULL) return;
   442→    serverAssert(!listNodeValue(ln));
   443→
   444→    /* Normally we fill this dummy NULL node, added by addReplyDeferredLen(),
   445→     * with a new buffer structure containing the protocol needed to specify
   446→     * the length of the array following. However sometimes when there is
   447→     * little memory to move, we may instead remove this NULL node, and prefix
   448→     * our protocol in the node immediately after to it, in order to save a
   449→     * write(2) syscall later. Conditions needed to do it:
   450→     *
   451→     * - The next node is non-NULL,
   452→     * - It has enough room already allocated
   453→     * - And not too large (avoid large memmove) */
   454→    if (ln->next != NULL && (next = listNodeValue(ln->next)) &&
   455→        next->size - next->used >= lenstr_len &&
   456→        next->used < PROTO_REPLY_CHUNK_BYTES * 4) {
   457→        memmove(next->buf + lenstr_len, next->buf, next->used);
   458→        memcpy(next->buf, lenstr, lenstr_len);
   459→        next->used += lenstr_len;
   460→        listDelNode(c->reply,ln);
   461→    } else {
   462→        /* Create a new node */
   463→        clientReplyBlock *buf = zmalloc(lenstr_len + sizeof(clientReplyBlock));
   464→        /* Take over the allocation's internal fragmentation */
   465→        buf->size = zmalloc_usable(buf) - sizeof(clientReplyBlock);
   466→        buf->used = lenstr_len;
   467→        memcpy(buf->buf, lenstr, lenstr_len);
   468→        listNodeValue(ln) = buf;
   469→        c->reply_bytes += buf->size;
   470→    }
   471→    asyncCloseClientOnOutputBufferLimitReached(c);
   472→}
