  2139→/* Rewrite the command vector of the client. All the new objects ref count
  2140→ * is incremented. The old command vector is freed, and the old objects
  2141→ * ref count is decremented. */
  2142→void rewriteClientCommandVector(client *c, int argc, ...) {
  2143→    va_list ap;
  2144→    int j;
  2145→    robj **argv; /* The new argument vector */
  2146→
  2147→    argv = zmalloc(sizeof(robj*)*argc);
  2148→    va_start(ap,argc);
  2149→    for (j = 0; j < argc; j++) {
  2150→        robj *a;
  2151→
  2152→        a = va_arg(ap, robj*);
  2153→        argv[j] = a;
  2154→        incrRefCount(a);
  2155→    }
  2156→    /* We free the objects in the original vector at the end, so we are
  2157→     * sure that if the same objects are reused in the new vector the
  2158→     * refcount gets incremented before it gets decremented. */
  2159→    for (j = 0; j < c->argc; j++) decrRefCount(c->argv[j]);
  2160→    zfree(c->argv);
  2161→    /* Replace argv and argc with our new versions. */
  2162→    c->argv = argv;
  2163→    c->argc = argc;
  2164→    c->cmd = lookupCommandOrOriginal(c->argv[0]->ptr);
  2165→    serverAssertWithInfo(c,NULL,c->cmd != NULL);
  2166→    va_end(ap);
  2167→}
